import React from "react"
import { Link, graphql } from "gatsby"

import Bio from "../components/bio"
import Layout from "../components/layout"
import SEO from "../components/seo"
import Tags from "../components/tags/tags"

// TODO migrate to tsx
const BlogPostTemplate = ({ data, pageContext, location }) => {
  const post = data.markdownRemark
  const { previous, next } = pageContext

  return (
    <Layout location={location} title="Blog">
      <SEO
        title={post.frontmatter.title}
        description={post.frontmatter.description || post.excerpt}
      />
      <article>
        <header>
          <h1 className="antialiased font-bold text-5xl tracking-wide">
            {post.frontmatter.title}
          </h1>
          <p className="pill bg-gray-300">{post.frontmatter.date}</p>
        </header>
        <section
          className="markdown space-y-4 py-4"
          dangerouslySetInnerHTML={{ __html: post.html }}
        />
        <div>
          <Tags tags={post.frontmatter.tags} />
        </div>
        <nav className="py-2">
          <ul
            style={{
              display: `flex`,
              flexWrap: `wrap`,
              justifyContent: `space-between`,
              listStyle: `none`,
              padding: 0,
            }}
          >
            {previous && (
              <li className="inline-block border border-blue-500 rounded py-1 px-3 bg-blue-500 text-white">
                <Link to={previous.fields.slug} rel="prev">
                  ← {previous.frontmatter.title}
                </Link>
              </li>
            )}
            {next && (
              <li className="inline-block border border-blue-500 rounded py-1 px-3 bg-blue-500 text-white">
                <Link to={next.fields.slug} rel="next">
                  {next.frontmatter.title} →
                </Link>
              </li>
            )}
          </ul>
        </nav>
        <footer>
          <Bio />
        </footer>
      </article>
    </Layout>
  )
}

export default BlogPostTemplate

export const pageQuery = graphql`
  query BlogPostBySlug($slug: String!) {
    markdownRemark(fields: { slug: { eq: $slug } }) {
      id
      excerpt(pruneLength: 160)
      html
      frontmatter {
        tags
        title
        date(formatString: "MMMM DD, YYYY")
        description
      }
    }
  }
`
