import React from "react"

export interface TagInterface {
  selectedTags: Array<string>
  tag: string
  updateTags: (tags: Array<string>) => void
}

const Tag: React.FunctionComponent<TagInterface> = props => {
  const updateTags = () => {
    let tags = []
    if (props.selectedTags.includes(props.tag)) {
      tags = props.selectedTags.filter(tag => tag != props.tag)
    } else {
      tags = props.selectedTags.concat([props.tag])
    }
    props.updateTags(tags)
  }
  return (
    <small className="bg-red-200 pill text-sm ml-1">
      <button onClick={updateTags}>{props.tag}</button>
    </small>
  )
}

export default Tag
